mapper.select:
select id, document_id, job_type, status, total_documents, indexed_documents, failed_documents, message, started_at, finished_at, created_at from cook_ai_knowledge_index_jobs
document_id = #{documentId}
order by created_at desc, id desc

mapper.update:
update cook_ai_knowledge_index_jobs
set total_documents = #{totalDocuments},
    indexed_documents = #{indexedDocuments},
    failed_documents = #{failedDocuments},
    message = #{message}
where id = #{id}
